steps.script:
() => {
  return {
    url: location.href,
    title: document.title,
    bodyText: document.body.innerText.slice(0, 3000),
    allForms: [...document.querySelectorAll('form')].map(f => ({
      id: f.id, action: f.action, classes: f.className.slice(0,100),
      html: f.outerHTML.slice(0,500)
    })),
    allInputs: [...document.querySelectorAll('input')].map(i => ({
      type: i.type, name: i.name, placeholder: i.placeholder,
      classes: i.className.slice(0,80), id: i.id
    })),
    allButtons: [...document.querySelectorAll('button, a[href], input[type=submit]')]
      .map(b => ({
        tag: b.tagName, text: (b.textContent||b.value||'').trim().slice(0,60),
        href: b.href||null, type: b.type||null, classes: b.className.slice(0,80)
      }))
      .filter(b => b.text)
      .slice(0, 20),
    klaviyoForms: [...document.querySelectorAll('[class*="klaviyo"], [data-form-id], .klaviyo-form')]
      .map(e => ({tag: e.tagName, classes: e.className.slice(0,100), id: e.id, dataFormId: e.getAttribute('data-form-id')})),
    images: [...document.querySelectorAll('img')].map(i => ({src: i.src.slice(0,120), alt: i.alt})).slice(0,10),
    h1s: [...document.querySelectorAll('h1,h2,h3')].map(h => h.textContent.trim()).filter(Boolean).slice(0,15)
  }
}
